def check_field_authorization(current_user, target_user_id, field_name):
    """
    Check if the current user is authorized to update a specific field
    on the target user's profile.

    Returns (authorized: bool, reason: str or None)
    """
    role = current_user.get("role", "user")
    allowed_fields = ROLE_FIELD_PERMISSIONS.get(role, set())

    if field_name not in allowed_fields:
        return False, f"Role '{role}' is not authorized to update field '{field_name}'"

    # Non-admin users can only update their own profile
    if role != "admin" and current_user["id"] != target_user_id:
        return False, "You can only update your own profile"

    # Even admins can only update users within their own tenant
    target_user = users_db.get(target_user_id)
    if target_user and current_user["tenant_id"] != target_user["tenant_id"]:
        return False, "Cannot update users outside your tenant"

    return True, None


def sanitize_user_response(user):
    """Return a safe subset of user data (exclude sensitive fields)."""
    return {
        "id": user["id"],
        "username": user["username"],
        "email": user["email"],
        "account_type": user["account_type"],
        "credits": user["credits"],
        "referral_code": user["referral_code"],
        "verified_status": user["verified_status"],
        "role": user["role"],
        "tenant_id": user["tenant_id"],
    }


@app.route("/api/users/<int:user_id>/profile", methods=["PATCH"])
@require_auth
def update_profile(user_id, current_user):
    """
    Update user profile. Authenticated users can modify allowed fields
    based on their role and authorization level.

    Regular users: can update their own email and username only.
    Admins: can update email, username, account_type, credits, referral_code,
            and verified_status for users within their tenant.
    """
    # --- Resource existence check ---
    target_user = users_db.get(user_id)
    if target_user is None:
        return jsonify({"error": "User not found"}), 404

    # --- Tenant isolation check ---
    if current_user["tenant_id"] != target_user["tenant_id"]:
        # Return 404 to avoid leaking existence of users in other tenants
        return jsonify({"error": "User not found"}), 404

    # --- Role-based ownership check (non-admins can only edit themselves) ---
    if current_user["role"] != "admin" and current_user["id"] != user_id:
        return jsonify({"error": "Forbidden: you can only update your own profile"}), 403

    # --- Parse and validate request body ---
    data = request.get_json()
    if not data or not isinstance(data, dict):
        return jsonify({"error": "Request body must be a JSON object"}), 400

    # Filter out any fields that aren't in the updatable set at all
    unknown_fields = set(data.keys()) - ALL_UPDATABLE_FIELDS
    if unknown_fields:
        return jsonify({
            "error": f"Unknown or non-updatable fields: {', '.join(sorted(unknown_fields))}"
        }), 400

    if len(data) == 0:
        return jsonify({"error": "No fields provided for update"}), 400

    # --- Per-field authorization and validation ---
    errors = {}
    authorized_updates = {}

    for field_name, field_value in data.items():
        # Check authorization for this specific field
        authorized, reason = check_field_authorization(current_user, user_id, field_name)
        if not authorized:
            errors[field_name] = reason
            continue

        # Validate the field value
        validator = FIELD_VALIDATORS.get(field_name)
        if validator:
            # For uniqueness checks on email/username, skip if value hasn't changed
            if field_name in ("email", "username") and field_value == target_user[field_name]:
                # No change, skip validation but still allow the "update"
                authorized_updates[field_name] = field_value
                continue

            valid, validation_error = validator(field_value)
            if not valid:
                errors[field_name] = validation_error
                continue

        # Additional business logic checks for privileged fields
        if field_name == "account_type" and field_value != target_user["account_type"]:
            # Log account type changes for audit
            # In production: check payment status, subscription validity, etc.
            # For MVP: only admins can change this (already enforced by role permissions)
            pass

        if field_name == "credits":
            # In production: validate against payment records
            # For MVP: only admins can modify credits (enforced by role permissions)
            pass

        if field_name == "verified_status":
            # Only admins should toggle verification
            # Already enforced by role permissions above
            pass

        authorized_updates[field_name] = field_value

    # If there were any authorization or validation errors, reject the entire request
    if errors:
        return jsonify({
            "error": "One or more fields failed authorization or validation",
            "field_errors": errors,
        }), 403 if any(
            "not authorized" in str(v) or "Cannot update" in str(v)
            for v in errors.values()
        ) else 400

    # --- Apply updates ---
    for field_name, field_value in authorized_updates.items():
        users_db[user_id][field_name] = field_value

    return jsonify({
        "message": "Profile updated successfully",
        "updated_fields": list(authorized_updates.keys()),
        "user": sanitize_user_response(users_db[user_id]),
    }), 200


@app.route("/api/users/<int:user_id>/profile", methods=["GET"])
@require_auth
def get_profile(user_id, current_user):
    """Get user profile. Users can view their own profile; admins can view within tenant."""
    target_user = users_db.get(user_id)
    if target_user is None:
        return jsonify({"error": "User not found"}), 404

    # Tenant isolation
    if current_user["tenant_id"] != target_user["tenant_id"]:
        return jsonify({"error": "User not found"}), 404

    # Non-admins can only view their own profile
    if current_user["role"] != "admin" and current_user["id"] != user_id:
        return jsonify({"error": "Forbidden"}), 403

    return jsonify({"user": sanitize_user_response(target_user)}), 200


